b:widget-settings.b:widget-setting:
/* Footer Social Icons */
                        .footer-sosmed-wrap {
                        display: flex;
                        justify-content: center;
                        align-items: center;
                        gap: 24px;
                        padding: 12px 0;
                        }
                        .footer-sosmed-wrap a {
                        font-size: 1.6rem;
                        color: #ffffff;
                        opacity: 0.7;
                        transition: opacity .2s, transform .2s;
                        display: inline-flex;
                        align-items: center;
                        text-decoration: none;
                        }
                        .footer-sosmed-wrap a:hover {
                        opacity: 1;
                        transform: translateY(-2px);
                        }
                        .footer-sosmed-wrap i {
                        font-style: normal;
                        display: inline-block;
                        line-height: 1;
                        }
                        .footer-sosmed-wrap i::before {
                        font-family: linkmagzfont !important;
                        font-weight: 400;
                        font-style: normal;
                        display: inline-block;
